#include<bits/stdc++.h>
using namespace std;
int main() {
    int n,m;
    cin>>n>>m;
    int b[n][m];
    for(int i=0;i<n;i++)
	{
        for(int j=0;j<m;j++)
		{
            cin>>b[i][j];
        }
    }
    for (int i=0;i<m;i++)
	{
        for (int j=0;j<n;j++)
		{
            cout<<b[n-1-j][i]<<" ";
        }
        cout<<endl;
    }
    return 0;
}
